    }

    r += '### Echantillon des 10 premiers articles uniques\n\n';
    articles.slice(0, 10).forEach((a, i) => { r += (i+1) + '. ' + (a.title || '?').substring(0, 100) + '\n'; });
} else if (mode === 'risk-of-bias') { /*ROB_REPORT*/
    r += '### Synthese de l evaluation du risque de biais\n\n';
    r += '- Articles evalues : **' + (stats.assessed || 0) + '**\n';
    r += '- Outils utilises : ' + (stats.tools_used || '-') + '\n';
    r += '- Base sur texte integral : ' + (stats.basis_fulltext || 0) + ' | sur abstract seul : ' + (stats.basis_abstract || 0) + '\n\n';
    const __rd = articles[0] && articles[0]._rob_double;
    if (__rd && __rd.enabled) {
      r += '### Double evaluation (accord inter-juges)\n\n';
      r += '- Modeles : ' + __rd.model_1 + ' vs ' + __rd.model_2 + '\n';
      r += '- Articles evalues 2x : ' + __rd.n_double + '\n';
      r += '- Accord niveau global : ' + (__rd.percent_agreement != null ? __rd.percent_agreement + '%' : 'n/a') + ' | accord moyen par item : ' + (__rd.mean_item_agreement != null ? __rd.mean_item_agreement + '%' : 'n/a') + '\n';
      r += '- kappa de Cohen (niveau global) : **' + __rd.cohen_kappa + '** (' + __rd.kappa_interpretation + ')\n\n';
    }
    r += '### Repartition du risque global\n\n';
    r += '- Faible (low) : ' + (stats.low_risk || 0) + '\n';
    r += '- Modere : ' + (stats.medium_risk || 0) + '\n';
    r += '- Eleve : ' + (stats.high_risk || 0) + '\n\n';
    const __hi = articles.filter(a => a._rob_level === 'high').slice(0, 10);
    if (__hi.length > 0) {
      r += '### Articles a risque eleve (top 10)\n\n';
      __hi.forEach(function(a, i){
        var __g = a._rob_overall || (a._rob_score!=null?(a._rob_score+'/'+a._rob_score_max):'');
        r += (i+1) + '. **' + (a.title||'?').substring(0,140) + '** [' + (a._rob_tool||'') + ' / ' + __g + ']\n';
        r += '   - ' + (a._rob_comment||'').substring(0,250) + '\n';
      });
    }
  }

  if (mode === 'snowballing') { /*SNOW_REPORT*/
    const __ss = (articles[0] && articles[0]._snowball_summary) || {};
    const real = articles.filter(a => !a._snowball_empty);
    r += '### Synthese du chainage de citations (snowballing)\n\n';
    r += '- Articles sources (seeds) : ' + (__ss.seeds||0) + ' (resolus OpenAlex : ' + (__ss.seeds_resolved||0) + ')\n';
    r += '- Direction : ' + (__ss.directions||'both') + ' | plafond citations entrantes/article : ' + (__ss.forward_cap||'-') + '\n';
    r += '- Candidats uniques trouves : **' + real.length + '**\n';
    r += '- Deja dans le corpus (retires) : ' + (__ss.removed_in_corpus||0) + '\n';
    if (__ss.by_source) { r += '- Par source : ' + Object.keys(__ss.by_source).map(function(s){ var v=__ss.by_source[s]||{}; return s+' (back '+(v.backward||0)+', fwd '+(v.forward||0)+')'; }).join(' ; ') + '\n'; }
    r += '- Backward (references) : ' + real.filter(a=>a._snowball_direction==='backward').length + ' | Forward (citations) : ' + real.filter(a=>a._snowball_direction==='forward').length + ' | Les deux : ' + real.filter(a=>a._snowball_direction==='both').length + '\n\n';
    const __multi = real.filter(a => (a._snowball_seed_count||1) > 1).sort((a,b)=>b._snowball_seed_count-a._snowball_seed_count).slice(0,10);
    if (__multi.length > 0) {
      r += '### Candidats lies a plusieurs sources (co-citation, prioritaires)\n\n';
      __multi.forEach(function(a,i){ r += (i+1)+'. **'+(a.title||'?').substring(0,140)+'** ('+a._snowball_seed_count+' sources, '+(a.cited_by_count||0)+' citations)\n'; });
      r += '\n';
    }
    const __top = real.slice(0,10);
    r += '### Top 10 candidats (par co-citation puis citations)\n\n';
    __top.forEach(function(a,i){ r += (i+1)+'. '+(a.title||'?').substring(0,140)+' _('+(a.year||'n.d.')+', '+(a._snowball_direction||'')+')_\n'; });
    r += '\n';
  }
  r += '\n---\n\n_Genere par UltraLab - https://github.com/yourrepo/ultralab_\n';
  return r;
}

