    const __cats=['Include','Maybe','Exclude']; const __c1={Include:0,Maybe:0,Exclude:0},__c2={Include:0,Maybe:0,Exclude:0}; let __nb=0,__ag=0;
    for (let __i=0; __i<results.length; __i++) {
